import { getData } from "../services/request";

const calc = (sizeSelect, materialSelect, optionsSelect, promoSelect, calcResSelect) => {
    const sizeElem = document.querySelector(sizeSelect),
        materialElem = document.querySelector(materialSelect),
        optionsElem = document.querySelector(optionsSelect),
        promoElem = document.querySelector(promoSelect),
        calcResElem = document.querySelector(calcResSelect);
    let discount = 1;

    function showOptions(arr, parentElem) {
        arr.forEach(item => {
            const {id, title, description, value} = item;
            
            const option = document.createElement('option');
            
            option.setAttribute('value', id);
            option.setAttribute('data-cost', value);
            if (title) option.setAttribute('title', title);
            option.textContent = description;

            parentElem.appendChild(option);
        });
        // parentElem.children[0].setAttribute('selected', true);
    }

    getData('http://localhost:3000/prices')
        .then(res => {
            showOptions(res.size, sizeElem);
            showOptions(res.material, materialElem);
            showOptions(res.options, optionsElem);
        });
    
    promoElem.addEventListener('input', (e) => {
        getData(`http://localhost:3000/promocode?name=${e.target.value}`)
        .then(res => {
            discount = res[0] ? res[0].value : 1;
            calcPrice();
        });
    });

    function calcPrice() {
        let size = +sizeElem.children[sizeElem.selectedIndex].getAttribute('data-cost'), 
            material = +materialElem.children[materialElem.selectedIndex].getAttribute('data-cost'),
            options = +optionsElem.children[optionsElem.selectedIndex].getAttribute('data-cost');
        
        let result = !size || !material ? 'Для расчета нужно выбрать размер картины и материал картины' : 
                Math.round((size * material + options) * discount);
                
        calcResElem.textContent = result;
    };

    sizeElem.addEventListener('input', calcPrice);
    materialElem.addEventListener('input', calcPrice);
    optionsElem.addEventListener('input', calcPrice);
};

export default calc;