import { getData } from "../services/request";

const showMoreStyles = (triggerSelector, parentSelector) => {
    const triggerBtn = document.querySelector(triggerSelector),
        parent = document.querySelector(parentSelector);

    for (let i = 0; i < parent.children.length; i++) {
        parent.children[i].classList.add('animated', 'fadeInUp');
    }

    const createStyleCard = (arr) => {
        const parent = document.querySelector(parentSelector);
        
        arr.forEach(({src, title, link}) => {
            const div = document.createElement('div');
            div.innerHTML = `
                        <div class=styles-block>
                            <img src='${src}' alt='${title}'>
                            <h4>${title}</h4>
                            <a href="${link}">Подробнее</a>
                        </div>`
            parent.appendChild(div).setAttribute('class', 'col-sm-3 col-sm-offset-0 col-xs-10 col-xs-offset-1 animated fadeInUp');
        })
    }

    triggerBtn.addEventListener('click', function(){
        getData('http://localhost:3000/styles')
            .then(res => createStyleCard(res))
            .catch(err => {
                const er = document.createElement('div');
                er.style.cssText = `text-align: center;
                            font-size: 2rem;
                            font-weight: 600;
                            margin: 10rem 0;`;
                er.textContent = err.message;
                parent.append(er);
            });
        triggerBtn.classList.add('animated', 'fadeOut');
        // triggerBtn.style.display = 'none';
        this.remove();
    });

};

export default showMoreStyles;