import { postData } from "../services/request";
// import {clearCalcData} from './modal';

const forms = () => {
    const forms = document.querySelectorAll('form'),
        uploads = document.querySelectorAll("input[name='upload']");

    const message = {
        loading: 'Завантаження...',
        success: "Дякуємо! Ми скоро з вам зв'яжемось!",
        failure: 'Щось пішло не за планом!((',
        spinner: 'assets/img/spinner.gif',
        ok: 'assets/img/ok.png',
        fail: 'assets/img/fail.png'
    };

    const servPath = {
        media: 'assets/designer.php',
        text: 'assets/server.php'
    }

    uploads.forEach(input => {
        input.addEventListener('input', () => {
            const arr = input.files[0].name.split('.');
            let dot = arr[0].length > 6 ? '...' : '.';
            const shortName = arr[0].slice(0, 6) + dot + arr[1];
            input.previousElementSibling.textContent = shortName;
        })
    });

    forms.forEach(form => {
        
        form.addEventListener('submit', (e) => {
            e.preventDefault();
            const messageBlock = document.createElement('div'),
                textBlock = document.createElement('div'),
                imgBlock = document.createElement('img');
                let url;
                
            messageBlock.classList.add('status');
            form.parentNode.append(messageBlock);
            form.classList.add('animated', 'fadeOut');
            form.style.display = 'none';
            
            textBlock.textContent = message.loading;
            imgBlock.setAttribute('src', message.spinner);

            form.classList.remove('fadeIn');
            messageBlock.classList.add('animated', 'fadeIn');

            messageBlock.append(imgBlock, textBlock);
        
            const formData = new FormData(form);

            url = form.closest('.popup-design') || form.closest('.calc') ? servPath.media : servPath.text;

            postData(url, formData)
                .then(res => {
                    console.log(res);
                    imgBlock.setAttribute('src', message.ok);
                    textBlock.textContent = message.success;
                })
                .catch(() => {
                    imgBlock.setAttribute('src', message.fail)
                    textBlock.textContent = message.failure;
                })
                .finally(() => {                    
                    form.reset();
                    uploads.forEach(input => {
                        input.previousElementSibling.textContent = 'Файл не найден. Загрузите или перетяните сюда ваши фото';
                    });
                    if (form.closest('.calc')) {
                        document.querySelector('.calc-price').textContent = 'Для расчета нужно выбрать размер картины и материал картины';
                    }
                    setTimeout(() => {
                        messageBlock.classList.remove('fadeIn');
                        messageBlock.classList.add('fadeOut');
                        messageBlock.remove();
                        
                        form.classList.remove('fadeOut');

                        form.classList.add('fadeIn');
                        form.style.display = 'block';
                
                    //     if(form.hasAttribute('data-calcform')) {
                    //         form.closest('.popup_calc_end').style.display = 'none';
                    //     }
                    //     clearCalcData();
                    }, 3000);
                });
        })
    });
};

export default forms;